int isIdentical(float *i, float *j, int D){
  int a = 0;
  int equal = 1;
  while (equal && D > a) {
    if (j[a] != i[a]) equal = 0;
    else a++;
  }
  if (equal) return 1;
  else return 0;
}

static int floatcomp(const void *i, const void *j)
{
  float a, b;
  a = *(float *)(i);
  b = *(float *)(j);
  if (b < a) return (1);
  if (b > a) return (-1);
  return(0);
}

void shuffle(Points *points)
{
  long i, j;
  Point temp;
  for (i=0;points->num-1 > i;i++) {
    j=(lrand48()%(points->num - i)) + i;
    temp = points->p[i];
    points->p[i] = points->p[j];
    points->p[j] = temp;
  }
}

void intshuffle(int *intarray, int length)
{
  long i, j;
  int temp;
  for (i=0;length > i;i++) {
    j=(lrand48()%(length - i))+i;
    temp = intarray[i];
    intarray[i]=intarray[j];
    intarray[j]=temp;
  }
}

